mapper.update:
UPDATE t_car_cost_etc_pay
SET waybill_id = #{waybillId}
WHERE etc_pay_id = #{etcPayId}

mapper.select:
SELECT ROUND(IFNULL(SUM(Amount), 0), 4)
FROM t_car_cost_etc_pay
WHERE waybill_id = #{waybillId} AND pay_mode = #{payMode} AND audit_status = #{auditStatus}

SELECT
ccep.vehicle_id,
SUM(ccep.amount) amount
FROM t_car_cost_etc_pay ccep
LEFT JOIN t_waybill w ON w.waybill_id = ccep.waybill_id
where DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime}
AND DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime}
and ccep.enterprise_id = #{queryForm.enterpriseId}
and ccep.vehicle_id in

    #{item}

GROUP BY ccep.vehicle_id

SELECT ccep.*, cct.tabulation_id, cct.module_id, cct.module_type, w.waybill_number, w.container_number, v.vehicle_number, d.driver_name, ccc.cost_type, ccc.category_name FROM t_car_cost_tabulation cct LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id LEFT JOIN t_vehicle v ON cct.vehicle_id = v.vehicle_id LEFT JOIN t_driver d ON cct.driver_id = d.driver_id LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id LEFT JOIN t_car_cost_etc_pay ccep ON cct.module_id = ccep.etc_pay_id
cct.tabulation_id IN
#{item}
